import dspy

class OverfitDetector:
    def __init__(self, module):
        self.module = module

    def detect(self, train_data, test_data, metric):
        train_scores = [metric(self.module(ex)) for ex in train_data[:10]]
        test_scores = [metric(self.module(ex)) for ex in test_data[:10]]
        overfitting_ratio = sum(train_scores) / sum(test_scores)
        return overfitting_ratio > 2.0, {'train_avg': sum(train_scores)/len(train_scores), 'test_avg': sum(test_scores)/len(test_scores)}

import dspy
from functools import wraps

def assertion_monitor(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        try:
            result = fn(*args, **kwargs)
            return result
        except AssertionError as e:
            print(f'Assertion failed: {e}')
            return {'error': str(e), 'failed_input': kwargs.get('example', 'unknown')}
    return wrapper

# Usage
basicQA = dspy.ChainOfThought('question -> answer')
basicQA.forward = assertion_monitor(basicQA.forward)

import re
import dspy

def validate_cot_logic(thought: str) -> dict:
    logic_patterns = {
        'step_count': r'\b(step|then|next|so|therefore)\b',
        'conclusion_markers': r'\b(final|answer|conclusion)\b',
        'contradictions': r'\b(but|however|contradict)\b'
    }

    metrics = {k: len(re.findall(v, thought.lower())) for k,v in logic_patterns.items()}
    metrics['has_reasoning'] = len(re.findall(logic_patterns['step_count'], thought.lower())) > 1
    metrics['logical'] = metrics['step_count'] > 0 and metrics['contradictions'] == 0
    return metrics

# Usage in DSPy signature
class ValidatedCoT(dspy.Signature):
    reasoning: str = dspy.OutputField()
    answer: str = dspy.OutputField()

    def post_forward(self, example, trace):
        cot_metrics = validate_cot_logic(trace['reasoning'])
        return {**trace, 'cot_valid': cot_metrics['logical']}

