import dspy
import vex

class VexDSPyAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.qa = dspy.ChainOfThought('question, context -> reasoning, answer')

    @vex.verify([
        "result['reasoning'] is not None and len(result['reasoning']) > 20",
        "result['answer'] is not None and len(result['answer']) > 10",
        "'because' in result['reasoning'].lower() or 'therefore' in result['reasoning'].lower()",
        "not result['answer'].startswith('I don't know')"
    ])
    def forward(self, question):
        context = dspy.Retrieve(k=3)(question).passages
        result = self.qa(question=question, context=context)
        return result

    def predict_with_fallback(self, question):
        try:
            return self.forward(question)
        except vex.VerificationError as e:
            print(f'Vex caught: {e.failures}')
            return {'answer': 'Unable to answer reliably', 'reasoning': 'Verification failed'}

# Usage
agent = VexDSPyAgent()
result = agent.predict_with_fallback('What is DSPy?')
